const v = $input.first().json;
const conversas = v.conversas_json || [];

// Sumariza dados para o prompt (evita token explosion)
const amostra = conversas.slice(0, 20); // top 20 mais recentes

const resumo_conversas = amostra.map((c, i) => {
  const args = (c.argumentos || []).filter(a => a.efetivo).map(a => a.texto).slice(0,3);
  const obs = (c.objecoes || []).map(o => `${o.tipo}(${o.contornada ? 'contornou' : 'perdeu'})`).slice(0,3);
  const flags = (c.flags || []).slice(0,2);
  return `[${i+1}] ${c.tipo_venda || '?'} | resultado:${c.resultado} | score:${c.score} | tom:${c.tom} | args:[${args.join('; ')}] | objeções:[${obs.join(', ')}]${flags.length ? ' | flags:['+flags.join(',')+']' : ''} | padrão:${c.padrao || '?'}`;
}).join('\n');

const prompt = `Você é um especialista em análise comportamental de vendedores.

Analise o histórico de conversas do vendedor "${v.vendedor_nome}" e gere um perfil comportamental detalhado.

Dados agregados:
- Total de conversas analisadas: ${v.total_conversas}
- Score médio de qualidade: ${v.score_medio}/10
- Taxa de conversão: ${v.taxa_conversao}%
- Tipo de venda predominante: ${v.tipo_venda_predominante || 'variado'}
- Tom predominante: ${v.tom_predominante || 'variado'}

Amostra das conversas recentes (${amostra.length} mais recentes):
${resumo_conversas}

Retorne APENAS um JSON válido (sem markdown) com esta estrutura:
{
  "estilo_persuasao": "descrição concisa do estilo único deste vendedor",
  "tipo_venda_afinidade": "varejo" | "consultiva" | "despertar_desejo",
  "tom_predominante": "tecnico" | "emocional" | "relacional" | "direto" | "misto",
  "pontos_fortes": [
    "ponto forte 1 específico com exemplo",
    "ponto forte 2",
    "ponto forte 3"
  ],
  "gaps": [
    "gap 1 específico com impacto na conversão",
    "gap 2"
  ],
  "recomendacoes": [
    {"acao": "ação específica de melhoria", "impacto": "alto|medio|baixo", "prazo": "imediato|semana|mes"}
  ],
  "padrao_dominante": "padrão comportamental mais característico deste vendedor"
}`;

return [{
  json: {
    vendedor_id:    v.vendedor_id,
    vendedor_nome:  v.vendedor_nome,
    total_conversas: v.total_conversas,
    score_medio:    v.score_medio,
    taxa_conversao: v.taxa_conversao,
    tipo_venda_predominante: v.tipo_venda_predominante,
    tom_predominante: v.tom_predominante,
    prompt
  }
}];

