const ctx = $('preparar-prompt-perfil').first().json;
const claudeResponse = $input.first().json;

let perfil;
try {
  const content = claudeResponse.content?.[0]?.text || '{}';
  perfil = JSON.parse(content);
} catch(e) {
  perfil = { estilo_persuasao: 'Erro ao gerar perfil', pontos_fortes: [], gaps: [], recomendacoes: [] };
}

const valido_ate = new Date();
valido_ate.setDate(valido_ate.getDate() + 30); // perfil válido por 30 dias

return [{
  json: {
    vendedor_id:           ctx.vendedor_id,
    tipo_venda_afinidade:  perfil.tipo_venda_afinidade  || ctx.tipo_venda_predominante,
    tom_predominante:      perfil.tom_predominante      || ctx.tom_predominante,
    estilo_persuasao:      perfil.estilo_persuasao      || '',
    pontos_fortes:         perfil.pontos_fortes         || [],
    gaps:                  perfil.gaps                  || [],
    recomendacoes:         perfil.recomendacoes         || [],
    taxa_conversao_media:  ctx.taxa_conversao,
    score_medio:           ctx.score_medio,
    total_conversas:       ctx.total_conversas,
    valido_ate:            valido_ate.toISOString()
  }
}];
